import anthropic

client = anthropic.Anthropic()

# Model registry: tier -> model ID
MODELS = {
    "fast": "claude-haiku-3-5",      # Tier 1: classification, extraction
    "balanced": "claude-sonnet-4",   # Tier 2: reasoning, tool use
    "powerful": "claude-opus-4",     # Tier 3: complex synthesis
}

def classify_intent(user_message: str) -> dict:
    """Route to fast model: simple classification, structured output."""
    response = client.messages.create(
        model=MODELS["fast"],
        max_tokens=64,
        system="Classify the user intent. Reply with JSON: {\"intent\": str, \"complexity\": \"low\" | \"medium\" | \"high\"}",
        messages=[{"role": "user", "content": user_message}],
    )
    import json
    return json.loads(response.content[0].text)


def draft_response(user_message: str, context: str) -> str:
    """Route to balanced model: needs reasoning and coherent prose."""
    response = client.messages.create(
        model=MODELS["balanced"],
        max_tokens=512,
        messages=[
            {"role": "user", "content": f"Context: {context}\n\nUser: {user_message}"},
        ],
    )
    return response.content[0].text


def deep_analysis(document: str, question: str) -> str:
    """Route to powerful model: long document, nuanced reasoning."""
    response = client.messages.create(
        model=MODELS["powerful"],
        max_tokens=2048,
        messages=[
            {"role": "user", "content": f"Document:\n{document}\n\nQuestion: {question}"},
        ],
    )
    return response.content[0].text


# Pipeline: classify first (fast), then route by complexity
def handle_request(user_message: str, context: str = "") -> str:
    classification = classify_intent(user_message)
    complexity = classification["complexity"]

    if complexity == "low":
        return draft_response(user_message, context)
    elif complexity == "medium":
        return draft_response(user_message, context)
    else:
        return deep_analysis(context, user_message)
